mapper.select:
SELECT * FROM ( SELECT x.*, ROW_NUMBER() OVER(
) AS rn FROM ( SELECT c.comment_id AS commentId, c.account_id AS authorAccountId, d.profile_image_url AS profileImageUrl, d.nickname AS nickname, d.handle AS handle, d.role_type AS roleType, c.status AS status, c.created_at AS createdAtRaw, TO_CHAR(c.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, c.content AS content FROM comments c JOIN vw_account_display d ON c.account_id = d.account_id
) x ) WHERE rn BETWEEN #{startRow} AND #{endRow} ORDER BY rn
